import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { useAuth } from './useAuth';

describe('useAuth', () => {
  let result: ReturnType<typeof useAuth>;

  beforeEach(() => {
    // Reset any previous state before each test
    result = useAuth();
  });

  afterEach(() => {
    // Clean up possible mock implementations
    vi.restoreAllMocks();
  });

  it('should handle happy path by providing default auth structure', () => {
    expect(result).toHaveProperty('user');
    expect(result).toHaveProperty('login');
    expect(result).toHaveProperty('logout');

    // default user should be null (not logged in)
    expect(result.user).toBeNull();

    // login and logout should be functions
    expect(typeof result.login).toBe('function');
    expect(typeof result.logout).toBe('function');
  });

  it('should handle edge case where login resolves to a user object', async () => {
    // mock a successful login
    const mockUser = { id: '123', name: 'Test User' };
    const loginMock = vi.fn().mockResolvedValue(mockUser);
    const logoutMock = vi.fn();

    // replace the real login/logout with mocks
    (result as any).login = loginMock;
    (result as any).logout = logoutMock;

    const user = await result.login('valid-token');
    expect(loginMock).toHaveBeenCalledWith('valid-token');
    expect(user).toEqual(mockUser);
    // after login, user state should reflect the logged in user
    (result as any).user = user;
    expect(result.user).toEqual(mockUser);
  });

  it('should handle null/empty inputs gracefully', async () => {
    // When login is called with null/undefined/empty string it should not throw
    const loginMock = vi.fn().mockResolvedValue(null);
    (result as any).login = loginMock;

    const userNull = await result.login(null as any);
    const userUndefined = await result.login(undefined as any);
    const userEmpty = await result.login('' as any);

    expect(userNull).toBeNull();
    expect(userUndefined).toBeNull();
    expect(userEmpty).toBeNull();

    // logout should also be safe to call without errors
    const logoutMock = vi.fn();
    (result as any).logout = logoutMock;
    expect(() => result.logout()).not.toThrow();
    expect(logoutMock).toHaveBeenCalled();
  });
});